  "contar-lneas-en-batch": "<p style=\"text-align: center;\">&nbsp;<span style=\"font-family: georgia; font-size: large;\"><i>Codigo</i></span></p><p><br /></p><p>@ echo off</p><p>set hola=0</p><p>for /F %%i in (%1) do (</p><p><span style=\"white-space: pre;\">\t</span>set /a hola=1+hola</p><p>)</p><p>echo %hola%</p><p><br /></p><p style=\"text-align: center;\"><span style=\"font-family: georgia; font-size: large;\"><i>Ejecución</i></span></p><p style=\"text-align: center;\"><span style=\"font-family: georgia; font-size: large;\"></span></p><div class=\"separator\" style=\"clear: both; text-align: center;\"><span style=\"font-family: georgia; font-size: large;\"><iframe allowfullscreen=\"\" class=\"BLOG_video_class\" height=\"266\" src=\"https://www.youtube.com/embed/gZ85AzQc3pk\" width=\"342\" youtube-src-id=\"gZ85AzQc3pk\"></iframe></span></div><span style=\"font-family: georgia; font-size: large;\"><br /><i><br /></i></span><p></p>",
