  "dni-en-bach": "<p>&nbsp;<span style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">@echo off</span></p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">set /p dni= \"Introduce un NIF: \"</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">set cadena=TRWAGMYFPDXBNJZSQVHLCKE</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">set /a resultado=%dni%-(23*(%dni%/23))</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">:bucle</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">if %resultado%==0 goto fin</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">::resto --</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">set /a resultado-=1</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">set cadena=%cadena:~1,23%</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">::echo %cadena%</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">goto bucle</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">:fin</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">echo La letra del NIF es %cadena:~0,1%</p><p style=\"background-color: white; color: #666666; font-family: \"Trebuchet MS\", Trebuchet, Verdana, sans-serif; font-size: 13.2px;\">pause&gt;nul</p>",
