  "redes-hyper-v": "<h2 style=\"text-align: center;\">&nbsp;<span style=\"text-align: left;\">Redes en Disponibles</span></h2><p></p><ul><li style=\"text-align: left;\"><i>Red Externa</i></li><li style=\"text-align: left;\"><i>Red Interna</i></li><li style=\"text-align: left;\"><i>Red Privada</i></li></ul><p style=\"text-align: center;\"><iframe allowfullscreen=\"\" class=\"BLOG_video_class\" height=\"301\" src=\"https://www.youtube.com/embed/swCFRACmMVc\" width=\"484\" youtube-src-id=\"swCFRACmMVc\"></iframe></p><div class=\"separator\" style=\"clear: both; text-align: center;\"><br /><a href=\"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgjfY7Iky5CUsb8oL8d8vTGmsNmgvJeW8F7mdAseTIqAqqpFeNCtmZ_8_MwQB5ZxR4EgpFkQ8e7A1Tw8KfSQWaFY6sPMdvovVY50KeX957PrpID68pgektinhNBeCZPtRdx9-v7D1gCguqusUxfMvlvcJwYGEgMvrXHI592YiwFhhH3fmSG1Dj8Cc73UIk/s1009/Hyper-V%20Networks.png\" style=\"margin-left: 1em; margin-right: 1em;\"><img border=\"0\" data-original-height=\"745\" data-original-width=\"1009\" height=\"301\" src=\"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgjfY7Iky5CUsb8oL8d8vTGmsNmgvJeW8F7mdAseTIqAqqpFeNCtmZ_8_MwQB5ZxR4EgpFkQ8e7A1Tw8KfSQWaFY6sPMdvovVY50KeX957PrpID68pgektinhNBeCZPtRdx9-v7D1gCguqusUxfMvlvcJwYGEgMvrXHI592YiwFhhH3fmSG1Dj8Cc73UIk/w353-h261/Hyper-V%20Networks.png\" width=\"484\" /></a></div><br /><p><br /></p><p></p>",
